      if (
        event.data.defenderId === "player" &&
        isCloseCall(event.data.defenderHpAfter)
      ) {
        return [
          entry(index, "close_call", source, {
            title: "Close call",
            text: `You are struck down to ${event.data.defenderHpAfter} HP and keep moving.`,
          }),
