              varianceMultiplier: 1,
              defenderHpBefore: 4,
              defenderHpAfter: 0,
            },
          },
          {
            turn: 0,
            type: "entity_died",
            data: {
              entityId: "enemy#1",
              kind: "enemy",
              position: { x: 1, y: 1 },
              xpYield: 2,
            },
          },
        ],
        stateHash: "abc",
